     4→/// Mixin providing common pagination functionality for repositories
     5→///
     6→/// This mixin provides reusable methods for cursor-based and offset-based
     7→/// pagination. It can be used with any repository class to add pagination
     8→/// capabilities.
     9→///
    10→/// Example usage:
    11→/// ```dart
    12→/// class TripRepository with PaginatedRepositoryMixin {
    13→///   @override
    14→///   Future<PaginatedData<Trip>> getPaginatedTrips(PaginationParams params) async {
    15→///     // Implementation
    16→///   }
    17→/// }
    18→/// ```
    19→mixin PaginatedRepositoryMixin {
    20→  /// Default page size for pagination queries
    21→  static const int defaultPageSize = 20;
    22→
    23→  /// Maximum page size to prevent excessive data loading
    24→  static const int maxPageSize = 100;
    25→
    26→  /// Validates and adjusts page size to be within acceptable bounds
    27→  ///
    28→  /// Returns [pageSize] if it's within bounds, otherwise returns
    29→  /// [defaultPageSize] or [maxPageSize] as appropriate.
    30→  int validatePageSize(int? pageSize) {
    31→    if (pageSize == null || pageSize <= 0) {
    32→      return defaultPageSize;
    33→    }
    34→    if (pageSize > maxPageSize) {
    35→      return maxPageSize;
    36→    }
    37→    return pageSize;
    38→  }
    39→
    40→  /// Creates PageInfo for a paginated response (cursor-based)
    41→  ///
    42→  /// Parameters:
    43→  /// - [currentCursor]: The cursor used for this page
    44→  /// - [pageSize]: Number of items per page
    45→  /// - [itemsCount]: Actual number of items returned
    46→  /// - [hasNextPage]: Whether there are more items after this page
    47→  /// - [nextCursor]: Cursor for the next page (null if no more pages)
    48→  /// - [previousCursor]: Cursor for the previous page (null if first page)
